    private static DesignerComponentDescriptor CreateDescriptor(
        string componentType,
        Type clrType,
        string displayName,
        string category,
        string icon,
        bool allowedInPalette,
        bool isWrapper,
        bool isDeprecated,
        IReadOnlyList<string> slots,
        IReadOnlyList<ComponentParameterDescriptor> parameters)
        => new(componentType, clrType, displayName, category, icon, allowedInPalette, isWrapper, isDeprecated, slots, parameters);

    private static ComponentParameterDescriptor CreateParameter(
        string name,
        string typeName,
        Type parameterType,
        string defaultValue,
        string description,
        bool isBindable,
        bool isEditorRequired,
        bool isEventCallback,
        bool isRenderFragment,
        bool isTemplatedRenderFragment)
        => new(name, typeName, parameterType, defaultValue, description, isBindable, isEditorRequired, isEventCallback, isRenderFragment, isTemplatedRenderFragment);
